VALUES
  ('elementary-8b44517b-moex-00647', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依性別工作平等法之規定，雇主於女性受僱者分娩前後，應使其停止工作，給予產假幾星期？', '["2星期", "5星期", "8星期", "16星期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00648', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依性別工作平等法之規定，關於受僱者申請育嬰留職停薪，下列何者錯誤？', '["受僱者任職滿六個月後，於每一子女滿三歲前，得申請育嬰留職停薪，期間至該子女滿三歲止，但不 得逾二年", "同時撫育子女二人以上者，其育嬰留職停薪期間應合併計算，最長以最幼子女受撫育二年為限", "受僱者申請育嬰留職停薪期間，薪資照給", "受僱者於育嬰留職停薪期間，得繼續參加原有之社會保險，原由雇主負擔之保險費，免予繳納；原由 受僱者負擔之保險費，得遞延三年繳納"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00649', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依勞動基準法之規定，下列關於派遣事業單位之敘述，何者錯誤？', '["派遣事業單位是指從事勞動派遣業務之事業單位", "派遣事業單位與派遣勞工訂定之勞動契約，應為不定期契約", "派遣事業單位與派遣勞工簽訂勞動契約前，得邀請要派單位面試該派遣勞工", "要派單位使用派遣勞工發生職業災害時，要派單位應與派遣事業單位連帶負勞動基準法所定雇主應負 職業災害補償之責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00650', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依勞動基準法之規定，雇主與勞工為離職後競業禁止之約定，應遵守下列何項規定？', '["雇主於勞工工作期間，給付勞工未來將因不從事競業行為而可能所受損失之合理補償", "雇主為勞工進行專業技術培訓，並提供該項培訓費用", "基於企業經營上所必須，且不得有不當動機及目的", "勞工擔任之職位或職務，能接觸或使用雇主之營業秘密"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00651', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依勞動基準法之規定，下列何者非屬雇主得不經預告終止契約之事由？', '["勞工受有期徒刑以上刑之宣告確定，而未諭知緩刑或未准易科罰金者", "勞工對於所擔任之工作確不能勝任時", "勞工故意損耗機器、工具、原料、產品，或其他雇主所有物品，或故意洩漏雇主技術上、營業上之秘 密，致雇主受有損害", "勞工無正當理由繼續曠工三日，或一個月內曠工達六日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00652', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依相關勞動法令之規定，勞工於下列何種未提供勞務期間，雇主不需繼續給付勞工工資？', '["女性勞工受僱工作在六個月以上，於分娩前後之停止工作的產假期間", "勞工之特別休假期間", "受僱者於其家庭成員預防接種、發生嚴重之疾病或其他重大事故須親自照顧，而請家庭照顧假之期間", "受僱者妊娠期間，雇主應給予產檢假的五日期間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00653', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依勞動基準法之規定，雇主有使勞工在正常工作時間以外工作之必要，且在一日不得超過十二小時的範 圍內，下列何項規定非屬雇主應遵守者？', '["雇主應經工會同意，如事業單位無工會者，應經勞資會議之同意", "雇主依勞工意願選擇補休並經雇主同意者，應依勞工工作之時數計算補休時數", "延長工作時間之工資，依勞動基準法第24條標準加給", "應報當地主管機關備查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00654', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依職業災害勞工保護法之規定，勞工保險之被保險人，在保險有效期間，於本法施行後遭遇職業災害， 不得向勞動部勞工保險局申請下列何種補助？', '["勞工在醫療中不能工作時，依原領工資數額所請求之補償", "罹患職業疾病，喪失部分或全部工作能力，經請領勞工保險各項職業災害給付後，所欲請領之生活津貼", "因職業災害致遺存障害，必需使用輔助器具，且未依其他法令規定領取器具補助，所欲請領之器具補助", "因職業災害致喪失全部或部分生活自理能力，確需他人照顧，且未依其他法令規定領取有關補助，所 欲請領之看護補助"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00655', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依勞動檢查法之規定，下列有關工會於勞動檢查中的敘述，何者錯誤？', '["勞工向工會申訴之案件，由工會依申訴內容查證後，提出書面改善建議送事業單位，並副知申訴人及 勞動檢查機構", "事業單位拒絕工會依申訴內容查證後，所提出之書面改善建議，工會得向勞動檢查機構申請實施檢查", "勞動檢查法所定告知工會陪同檢查人員身分範圍，限於受檢事業單位所僱勞工", "勞動檢查員執行職務時，得就勞動檢查範圍，對工會代表詢問，必要時並得製作談話紀錄或錄音"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00656', 'elementary-8b44517b', 'elementary-8b44517b-moex-111-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列何者非公立就業服務機構促進就業之措施？', '["為婦女舉辦職業訓練", "推介身心障礙者就業後，辦理追蹤訪問", "協助推介退伍者參加職業訓練", "協助推介更生受保護人參加職業訓練"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:33+00:00", "source_pdf_sha1": "4ae176d8d1b5", "answer_pdf_sha1": "6d2843534a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
